#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=5e5+5;

struct Node{
    ll sum,gcd;
}t[4*N];

int n,m;
ll a[N];

void build(int cur,int l,int r){
    if(l==r){
        t[cur]={a[l],a[l]};
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]={t[cur*2].sum+t[cur*2+1].sum,__gcd(t[cur*2].gcd,t[cur*2+1].gcd)};
}

void modify(int cur,int l,int r,int x,ll k){
    if(l==r){
        t[cur]={t[cur].sum+k,t[cur].gcd+k};
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,k);
    else
        modify(cur*2+1,mid+1,r,x,k);
    t[cur]={t[cur*2].sum+t[cur*2+1].sum,__gcd(t[cur*2].gcd,t[cur*2+1].gcd)};
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1;
    Node ans={0,0};
    if(x<=mid){
        Node tmp=query(cur*2,l,mid,x,y);
        ans={ans.sum+tmp.sum,__gcd(tmp.gcd,ans.gcd)};
    }
    if(y>mid){
        Node tmp=query(cur*2+1,mid+1,r,x,y);
        ans={ans.sum+tmp.sum,__gcd(tmp.gcd,ans.gcd)};
    }
    return ans;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%lld",&a[i]);
    for(int i=n;i;i--)
        a[i]-=a[i-1];
    build(1,1,n);
    while(m--){
        char op[2];
        int l,r;
        scanf("%s%d%d",op,&l,&r);
        if(op[0]=='C'){
            ll d;
            scanf("%lld",&d);
            modify(1,1,n,l,d);
            if(r<n)
                modify(1,1,n,r+1,-d);
        }else{
            if(l<r)
                printf("%lld\n",abs(__gcd(query(1,1,n,1,l).sum,query(1,1,n,l+1,r).gcd)));
            else
                printf("%lld\n",query(1,1,n,1,l).sum);
        }
    }
    return 0;
}
